export default App;

import React, { useEffect, useRef, useState } from 'react';
import { ArrowRight, PlayCircle } from 'lucide-react';
import DashboardMockup from './DashboardMockup';
import { FEATURES } from '../constants';

const Hero: React.FC = () => {
  const [visibleFeatures, setVisibleFeatures] = useState<number[]>([]);
  const featuresRef = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const index = Number(entry.target.getAttribute('data-index'));
            if (!Number.isNaN(index)) {
              setVisibleFeatures((prev) => {
                if (prev.includes(index)) return prev;
                return [...prev, index];
              });
              // Stop observing once visible so it doesn't fade out/in again
              observer.unobserve(entry.target);
            }
          }
        });
      },
      {
        threshold: 0.2, // Trigger when 20% of the item is visible
        rootMargin: '0px 0px -50px 0px'
      }
    );

    featuresRef.current.forEach((el) => {
      if (el) observer.observe(el);
    });

    return () => {
      observer.disconnect();
    };
  }, []);

  return (
    <section className="relative w-full min-h-screen overflow-hidden bg-[#FAFAF9] flex items-center pt-20 pb-20 lg:pt-0 lg:pb-0">

      {/* Background Decorative Blur (Left side subtle) */}
      <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-blue-50/50 rounded-full blur-[120px] -translate-x-1/2 -translate-y-1/2 pointer-events-none" />

      <div className="container mx-auto px-4 md:px-6 lg:px-12 max-w-7xl relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-8 items-center">

          {/* LEFT COLUMN: Content */}
          <div className="flex flex-col items-start max-w-2xl mx-auto lg:mx-0 space-y-8 lg:pr-12">

            {/* Badge */}
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-white border border-gray-200 shadow-sm">
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
              <span className="text-xs font-semibold text-gray-600 tracking-wide uppercase">Real-time Finance Platform</span>
            </div>

            {/* Headlines */}
            <div className="space-y-6">
              <h1 className="text-5xl md:text-6xl lg:text-7xl font-semibold tracking-tighter text-gray-900 leading-[1.1]">
                Financial visibility,<br />
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-gray-900 to-gray-600">simplified.</span>
              </h1>
              <p className="text-xl text-gray-600 font-light leading-relaxed max-w-lg">
                Understand revenue, costs, and trends instantly—no spreadsheets required.
              </p>
            </div>

            {/* CTAs */}
            <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 w-full sm:w-auto">
              <button className="group relative px-8 py-4 bg-black text-white rounded-full font-medium text-lg shadow-xl hover:shadow-2xl hover:scale-105 transition-all duration-300 flex items-center justify-center gap-3 overflow-hidden">
                <span className="relative z-10">Get Started</span>
                <div className="relative z-10 bg-white/20 rounded-full p-1 group-hover:translate-x-1 transition-transform">
                  <ArrowRight className="w-4 h-4" />
                </div>
                {/* Button shine effect */}
                <div className="absolute inset-0 -translate-x-full group-hover:translate-x-full transition-transform duration-1000 bg-gradient-to-r from-transparent via-white/10 to-transparent skew-x-12" />
              </button>

              <button className="group px-8 py-4 bg-white text-gray-900 border border-gray-200 rounded-full font-medium text-lg shadow-sm hover:shadow-lg hover:border-gray-300 transition-all duration-300 flex items-center justify-center gap-3">
                <PlayCircle className="w-5 h-5 text-gray-400 group-hover:text-gray-900 transition-colors" />
                View demo
              </button>
            </div>

            {/* Features List */}
            <div className="pt-8 grid grid-cols-1 sm:grid-cols-3 gap-6 w-full border-t border-gray-200/60 mt-4">
              {FEATURES.map((feature, index) => (
                <div 
                  key={index}
                  data-index={index}
                  ref={(el) => { featuresRef.current[index] = el; }}
                  className={`flex flex-col gap-3 group cursor-default transition-all duration-700 ease-out ${
                    visibleFeatures.includes(index) 
                      ? 'opacity-100 translate-y-0' 
                      : 'opacity-0 translate-y-8'
                  }`}
                  style={{ transitionDelay: `${index * 150}ms` }}
                >
                  <div className="w-10 h-10 rounded-xl bg-white border border-gray-200 shadow-sm flex items-center justify-center group-hover:border-gray-300 group-hover:shadow-md transition-all">
                    {feature.icon}
                  </div>
                  <div>
                    <h4 className="font-semibold text-gray-900 mb-1">{feature.title}</h4>
                    <p className="text-sm text-gray-500 leading-snug">{feature.description}</p>
                  </div>
                </div>
              ))}
            </div>

          </div>

          {/* RIGHT COLUMN: Dashboard Visual */}
          <div className="relative flex justify-center lg:justify-end items-center mt-12 lg:mt-0">
            <DashboardMockup />
          </div>

        </div>
      </div>
    </section>
  );
};

export default Hero;
